    // Use this Server side function to convert HTML to a simple string 
    convertHtmlToSimpleString: function(someHtmlText) {
        someHtmlText = someHtmlText + '';

        return someHtmlText.replace(/<\/?[^>]+(>|$)/g, '');
    },

