	// STRY0115436 - STRY0108687
	_getOUFieldListHoverArray: function(OUid, fieldName){
		var id = '';
		var oInfo = {};
		var aInfo = [];
		var aIds = [];
		var sIds = '';
		var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
		if(grOU.get(OUid)){
			sIds = grOU.getValue(fieldName);
			if(sIds){
				aIds = sIds.split(',');
			}
			// Loop through the array of ids
			for (var i = 0; i < aIds.length; i++){
				id = aIds[i];
				oInfo = this._loadUserHover(id);
				aInfo.push(oInfo);
			}
			if(aInfo.length > 0){
				aInfo = aInfo.sort(function(ha1, ha2) {
					if(ha1.name > ha2.name) return 1;
					if(ha1.name < ha2.name) return -1;
				});
			}
			return aInfo;
		}
	},

