			last_name: '',
			middle_name: '',
			email: '',
			businessPhone: '',
			mobilePhone: '',
			location: '',
			time_zone: '',
			contactPageHref: '',
			photo: '',
			connectEnabled: '',
			liveProfileId: '',
			messages: {},
			icons: {}
		};

		var grUser = new GlideRecord('sys_user');
		if(grUser.get(userGUID)){
			// 2.8 | 2022-03-04 | mmcc | STRY0114453 - Org Hierarchy Full Screen- Tree Node- Avatar Control- Popover Panel; 
			//  added getDisplayValue to many, .contactPageHref, mobile phone; Changed phone to businessPhone, add call to get Connect Chat fields
			userProfile.name = grUser.getDisplayValue('name');
			userProfile.first_name = grUser.getDisplayValue('first_name');
			userProfile.last_name = grUser.getDisplayValue('last_name');
			userProfile.middle_name = grUser.getDisplayValue('middle_name');
			userProfile.email = grUser.getDisplayValue('email');
			userProfile.businessPhone = grUser.getDisplayValue('phone');
			userProfile.mobilePhone = grUser.getDisplayValue('mobile_phone');
			userProfile.location = grUser.getDisplayValue('location');
			userProfile.contactPageHref = '?id=user_profile&sys_id=' + userGUID;

			// if no user time zone, but location is loaded
			if(grUser.time_zone){
