    // 2.7.0 | 2021-07-06 | mmcc | STRY0102408 Task Tree Manager tool tip displays Unicode
    // re-write function to use local var's; remove badgeclass and taskText.state
    getTaskTreeListTitleNode: function(newNodeData) {
        var assignedTo = '';
		var taskNameNumber = newNodeData.task_name;
        var taskText = {};

        if (newNodeData.parent != null) {
			taskNameNumber = newNodeData.order + ". " + newNodeData.task_name;
        }

        if (!!newNodeData.assigned_to && newNodeData.assigned_to != '') {
            assignedTo = '(' + newNodeData.assigned_to + ')';
        }

        taskText = {
            TaskNameNumber: taskNameNumber,
            primary_assignee: newNodeData.primary_assignee,
            assigned_to: assignedTo,
            state: newNodeData.state,
            Order: newNodeData.order
        };

        return taskText;
    },
	//DFCT0011078
	getTaskTitleNode: function(grTask) {
		// DFCT0011134 - STRY0127737 - change name and number display
        var nodeTitle = grTask.short_description.toString();
        if (grTask.parent != '') {
            nodeTitle = grTask.order.toString() + ". " + nodeTitle; // NEW
        }
		// DFCT0011227
		if(nodeTitle.length > TaskWidgetData.CONST_TREE_NAME_MAX_LENGTH){
			nodeTitle = nodeTitle.substring(0,TaskWidgetData.CONST_TREE_NAME_MAX_LENGTH) + "...";
		}
        return nodeTitle;
	},

    // SEQ - Task Details page – Displays Task Tree View Indicators
	// DFCT0011078
	// DFCT0011134 - STRY0127737 - change name and number display
    getTaskNodeDetails: function(grTask) {
        var nodeDetails = "";
        switch (grTask.state.getDisplayValue().toString()) {
            case 'Waiting':
                if (grTask.calchaschildren.getDisplayValue().toString() == '0'
                    //grTask.u_active_subtasks.getDisplayValue().toString() == grTask.calchaschildren.getDisplayValue().toString() && 
                )
                    nodeDetails += grTask.state.getDisplayValue().toString() + " on creating Subtasks ";
                else
                    nodeDetails += grTask.state.getDisplayValue().toString() + " on " + grTask.u_active_subtasks.getDisplayValue().toString() + " out of " + grTask.calchaschildren.getDisplayValue().toString() + " Subtasks";
                break;
            case 'Assigned':
                nodeDetails += grTask.state.getDisplayValue().toString() + " to " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'Accepted':
                nodeDetails += grTask.state.getDisplayValue().toString() + " by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'Work in Progress':
                nodeDetails += grTask.state.getDisplayValue().toString() + " by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'In Review':
                nodeDetails += grTask.state.getDisplayValue().toString() + " by " + grTask.u_reviewer.getDisplayValue().toString() + ", Worked by " + grTask.assigned_to.getDisplayValue().toString();
                break;
            case 'Completed':
				// STRY0128732 Task Tree- Improved Messaging for Decision Made on Approval and Concurrence Tasker Types
				if(grTask.decision && grTask.decision !="" && grTask.decision != 'N/A'){
					nodeDetails += grTask.decision + " by " + grTask.assigned_to.getDisplayValue().toString();

				} else {
					nodeDetails += grTask.state.getDisplayValue().toString() + " by " + grTask.assigned_to.getDisplayValue().toString();	
				}

                break;
            default:
                nodeDetails += grTask.state.getDisplayValue().toString();
                break;
        }
		// DFCT0011227
		if(nodeDetails.length > TaskWidgetData.CONST_TREE_DETAILS_MAX_LENGTH){
			nodeDetails = nodeDetails.substring(0,TaskWidgetData.CONST_TREE_DETAILS_MAX_LENGTH) + "...";
		}
        return nodeDetails;
    },

	// DFCT0011134 - STRY0127737 - change name and number display
	getTemplateNodeDetails: function(grTemplateTask) {
        var nodeDetails = '(' + grTemplateTask.primary_assignee.getDisplayValue().toString() + ')';
		// DFCT0011227
		if(nodeDetails.length > TaskWidgetData.CONST_TREE_DETAILS_MAX_LENGTH){
			nodeDetails = nodeDetails.substring(0,TaskWidgetData.CONST_TREE_DETAILS_MAX_LENGTH) + "...";
		}
        return nodeDetails;	
	},

