			nodeTitle = nodeTitle.substring(0,TaskWidgetData.CONST_TREE_NAME_MAX_LENGTH) + "...";
		}
        return nodeTitle;
    },

	// STRY0119587 - Task Form Page Layout- Layout: Requests
	// STRY0120403 changed structure to recieve single object and pass filter for all descendents
	loadRelatedLists: function(rlParms) {
		var tab_widget_related_lists = [];
		// STRY0120440
		var rlItem;
		for (var i in rlParms.f_related_lists) {
			// STRY0092475 - STRY0120440 - moved this up to set as default so the array from page options could override it
			var rlView = rlParms.view;	

			var rl = rlParms.f_related_lists[i];
			// STRY0120440
			if (rl.table == "x_153465_discovert_discover_tasker_response"){
				// NOTE: we may want to changet his based on whether single task or all descendents is the current filter
				rlView = "sp"; // override the default from tasker form with tabs for response log
			}

			// default show all related lists
			var showRL = true;
			// if documents not included, don't show attachments
			if(rl.table == "sys_attachment" ){
				// there was an issue where the Shared Attachment label was not plural
				// DFCT0011062 improves efficiency of what is loaded to HTML and removes all related lists except attachments if attachment is on
				if(rlParms.hideDocuments || 
					rlParms.attachmentsON == false ||
					((rl.label == "Shared Attachment") && (rlParms.attachmentSharedFolderON == false)) ||
					((rl.label == "Attachments") &&
						(rlParms.table == "x_153465_discovert_discover_routing_template") &&
						(rlParms.attachmentSharedFolderON == false))
					){
					showRL = false;
				}
			// DFCT0011062 improves efficiency of what is loaded to HTML and removes all related lists except attachments if attachment is on
			} else if(rlParms.hideRelatedLists){
				showRL = false;
			}else if(rlParms.arrRelatedLists && rlParms.arrRelatedLists.length > 0){
				// if an array of related lists was set in the widget options, then this list is not shown unless in the list
				showRL = false;
				for(var j = 0; j < rlParms.arrRelatedLists.length; j++) {
					// STRY0120440
					rlItem = rlParms.arrRelatedLists[j];
					if (rlItem.label == rl.label) {
						if(rlItem.view && rlItem.view!=''){
							// override the default view with the view passed in
							rlView = rlItem.view;
						}
						showRL = true;
						break;
					}
				}
			}
			rl.showList = showRL;
			if(!showRL){
				continue;
			}

			// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; pass the whole related list item
			// DFCT0010477
			//------------------------------------------------------------------------------------------------------------------------
			// 2.4. CUSTOM: RELATED LIST FILTER
			//------------------------------------------------------------------------------------------------------------------------
			var filter = rl.field + "=" + rlParms.rec.sys_id;
			// STRY0059424 | Include Attachments since we dropped attachment properties
			if ((rl.table == "sys_attachment") && (rl.label == "Shared Attachment") && (rlParms.attachmentSharedFolderON == true)) {
				// STRY0063505 |	Modified to set this above based on table
				filter = 'table_sys_id' + "=" + rlParms.sharedAttachSys_ID;
			} else {
				if ((rl.table == "sys_attachment") && (rl.label == "Attachments")) {
					// STRY0063505 |	Modified to set this above based on table
					filter = 'table_sys_id' + "=" + rlParms.myAttachSys_ID;
				}
			}
			rl.filter = filter;

			// STRY0059145 | The previous implementation was using just rl.table for the target inthe HTML for loading data and counts.
			// Any time the same table is added 2 times in the HTML, the target will be the same for both tables.  
			// a new field was created, rl.targetId, by concatenating rl.table with rl.label(without spaces).
			// this new field will be used instead of rl.table in the target fields of the HTML
			rl.targetId = rl.table + rl.label.replace(/ /g, "_");

			// STRY0128070 - updates for new button
			var newIconName;
			rl.hideRelatedList=false;
			//------------------------------------------------------------------------------------------------------------------------
			// 2.1. CUSTOM: RELATED LIST DETAIL OPEN MODE: MODAL OR REDIRECT?
			//------------------------------------------------------------------------------------------------------------------------
			var open_row_details_in_modal = false;

			//------------------------------------------------------------------------------------------------------------------------
			// 2.2. CUSTOM: RELATED LIST SORT AND DIRECTION
			//------------------------------------------------------------------------------------------------------------------------
			var o = "";
			var d = "";

			// STRY0046028 - determine if user can create for the related list
			var userInfoScript = new UserInfoScripts();
			switch (rl.table) {
				case "x_153465_discovert_tasker_requests":
					// don't allow to create from related list, need to create a request based on type.
					rl.canCreate = false;
					open_row_details_in_modal = true;
					rl.title = this._setDefaultTitle(rl);
					o = "number";
					d = "desc";
					break;
				case "x_153465_discovert_discover_office_members":
					rl.canCreate = userInfoScript.userCanCreateMem(rlParms.rec.sys_id);
					rl.title = gs.getMessage("Tasker - OU Members");
					rl.label = rl.title;
					rl.newModalTitle = gs.getMessage("Tasker - New OU Member");
					rl.newModalView = "";
					rl.newModalQuery = 'discover_office_hierarchy=' + rlParms.rec.sys_id;
					o = "office_member";
					d = "asc";
					open_row_details_in_modal = true;
					break;
				case "x_153465_discovert_discover_office_hierarchy":
					rl.canCreate = userInfoScript.userCanCreateOU(rlParms.rec.sys_id);
					rl.title = gs.getMessage("Tasker - Sub OUs");
					rl.label = rl.title;
					filter = filter + "^ORDERBYlevel_order^ORDERBYoffice_name";
					rl.filter = filter;
					rl.newModalTitle = gs.getMessage("Tasker - New Sub OU");
					rl.newModalView = "";
					rl.newModalQuery = 'parent=' + rlParms.rec.sys_id;
					break;
				case "x_153465_discovert_route_tasks":
					rl.canCreate = userInfoScript.userHasProcessRights(rlParms.rec);
					if (rlParms.page_id == "discovertasker_processtemplatedetails") open_row_details_in_modal = true;

					switch (rlParms.table) {
						case "x_153465_discovert_discover_routing_template":
							rl.hideRelatedList = true;
							rl.title = gs.getMessage("Tasker - Template Tasks");
							rl.label = rl.title;

							break;
						case "x_153465_discovert_route_tasks":
							rl.title = gs.getMessage("Tasker - Subtasks");
							rl.label = rl.title;

							rl.newModalTitle = gs.getMessage("Tasker - New Template Task");
							rl.newModalView = "Create_View";
							rl.newModalQuery = 'parent=' + rlParms.rec.sys_id;
							break;
						default:
							rl.title = gs.getMessage("Tasker - Template Tasks");
							rl.label = rl.title;
							break;

					}
					break;
				case "x_153465_discovert_tasker_schedule":
					// STRY0082332 - FIX: Template Designers can create Template Schedules
					rl.canCreate = new uiConditionCheck().runTemplateUIAction(rlParms.rec);
					rl.title = this._setDefaultTitle(rl);
					o = "next_run_date";
					d = "asc";
					rl.newModalTitle = gs.getMessage("Tasker - New Schedule");
					rl.newModalView = "Create_View";
					rl.newModalQuery = 'tasker_process=' + rlParms.rec.sys_id;
					break;
				case "x_153465_discovert_discover_routing_template":
					rl.canCreate = userInfoScript.userHasProcessRights(rlParms.rec);
					rl.title = this._setDefaultTitle(rl);
					// no new modal for routing template, don't add new button to screen
					break;

				case "x_153465_discovert_organizational_contacts":
					rl.canCreate = true;
					rl.title = gs.getMessage("Tasker - Contacts");
					rl.label = rl.title;
					o = "u_user_information";
					d = "asc";
					rl.newModalTitle = gs.getMessage("Tasker - New OU Contact");
					rl.newModalView = "";
					rl.newModalQuery = 'u_contact_ou=' + rlParms.rec.sys_id;
					// STRY0074663
					open_row_details_in_modal = true;
					break;
				case "x_153465_discovert_route_task_instance":
					rl.canCreate = rlParms.canCreateSubTask;
					o = "task_order";
					d = "asc";

					// STRY0128070 - updates for new button
					switch (rlParms.table) {
						case "x_153465_discovert_discover_routing_template":
							// STRY0097809
							rlView = "sp";
							rl.title = rl.label;

							rl.title = gs.getMessage("Tasker - Template Instances");
							rl.label = rl.title;
							o = "number";
							d = "desc";
							// STRY0092475 - related list uses a relationshiop and for some reason the rl.field value is undefined for relationships
							rl.field = 'u_parent_template';
							break;
						case "x_153465_discovert_route_task_instance":
							rl.title = gs.getMessage("Tasker - Subtasks");
							rl.label = rl.title;
							rl.newModalTitle = gs.getMessage('Create Subtask')  + ': ' + rlParms.rec.task_name;
							rl.newModalView = rlParms.view;
							rl.newModalQuery = 'parent=' + rlParms.rec.sys_id;
							// DFCT0011268
							rl.addIconTitle = gs.getMessage('Create Subtask');
							open_row_details_in_modal = true;
							break;
						case "x_153465_discovert_discover_office_hierarchy":
							rl.title = gs.getMessage("Tasker - Tasks");
							rl.label = rl.title;
							open_row_details_in_modal = true;
							break;
						default:
							rl.title = gs.getMessage("Tasker - Tasks");
							rl.label = rl.title;
							break;
					}

					break;
					// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
					// This will control showing a New button on the menu row for Tasker Emails tab
				case 'x_153465_discovert_tasker_email':
					rl.canCreate = rlParms.emailEnabled;
					open_row_details_in_modal = true;
					// STRY0128070 - updates for new button
					rl.hideRelatedList = !rlParms.emailEnabled;
					rl.title = gs.getMessage("Tasker - Tasker Emails");
					rl.label = rl.title;

					rl.newModalTitle = "N/A for email";
					rl.newModalView = "N/A for email";
					rl.newModalQuery = "N/A for email";
					rl.addIconTitle = gs.getMessage("Tasker - Create new Tasker Email");
					newIconName = 'NewMail24.svg';
					break;
				default:
					rl.canCreate = false;
					rl.title = this._setDefaultTitle(rl);
			}
			//------------------------------------------------------------------------------------------------------------------------
			//OVERRIDES FOR RELATED LIST DETAIL OPEN MODE: MODAL OR REDIRECT?
			//------------------------------------------------------------------------------------------------------------------------
			if (rlParms.table == "x_153465_discovert_discover_routing_template") open_row_details_in_modal = true;
			if (rlParms.table == "x_153465_discovert_war_sar_reporting") open_row_details_in_modal = true;
			if (rlParms.table == "x_153465_discovert_discover_tasker_response") open_row_details_in_modal = true;

			// DFCT0010784 - anything on the processing page should open in Modal
			if(rlParms.page_id == "discover_simple_processing_form" ||
				rlParms.page_id == "task_delegation_view") {
				open_row_details_in_modal = true;
			}			

			// DFCT0011162 -  DFCT0011236
			var params;
			if(rl.table == "sys_attachment"){
				// determining if the rl is shown, is handled above
				if(rl.showList == true){
					if((rl.label == "Shared Attachment")){
						params = {
							isModal: rlParms.isModal,
							bifold: rlParms.bifold,
							/* this is what you need to load widget from client						
							table: rlParms.sharedAttachTableName,
							sys_id: rlParms.sharedAttachSys_ID + "",
							name: 'sharedAttachmentWidget'
							*/
							record_table: rlParms.sharedAttachTableName,
							record_id: rlParms.sharedAttachSys_ID + "",
							record_name: 'sharedAttachmentWidget',
							// DFCT0011217
							task_id: rlParms.myAttachSys_ID
							};
						rl.widget = $sp.getWidget('tasker_task_attachments', params);
						tab_widget_related_lists.push(rl);						
					} else {
						params = {
							isModal: rlParms.isModal,
							bifold: rlParms.bifold,
							/* this is what you need to load widget from client													
							table: rlParms.table,
							sys_id: rlParms.rec.sys_id,
							name: 'myAttachmentWidget'
							*/							
							record_table: rlParms.table,
							record_id: rlParms.rec.sys_id + '',
							record_name: 'myAttachmentWidget',
							// DFCT0011217
							task_id: rlParms.myAttachSys_ID
						};
						rl.widget = $sp.getWidget('tasker_task_attachments', params);
						tab_widget_related_lists.push(rl);
					}
				}
			} else {
				//------------------------------------------------------------------------------------------------------------------------
				// 2.5. CUSTOM: WIDGET PARAMETERS
				//------------------------------------------------------------------------------------------------------------------------
				// NOTE: moved below the setting of canCreate so that can be used in the show_new
				params = {
					// STRY0120159 
					showStatesMultipleBar: rlParms.showStatesMultipleBar,
					hideTaskFilter: rlParms.hideTaskFilter,
					task_id: rlParms.task_id,
					// DFCT0011271
					u_servicenow_form_view: rlParms.u_servicenow_form_view,
					parentField: rl.field,
					o: o,
					d: d,
					table: rl.table,
					filter: filter,
					// STRY0107408
					show_new: rl.canCreate,
					open_new_in_modal: true,
					//STRY0092475: 04/01/2020
					view: rlView,
					title: rl.title,
					// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis added 
					isModal: rlParms.isModal,
					// 2.8 | 2022-08-01 | mmcc | DFCT0011122 - Page Task Requests needs to match the standard layout for flexing header-body-footer; add bifold
					// STRY0128070 - updates for new button
					newModalTitle: rl.newModalTitle,
					newIconName: newIconName,
					// DFCT0011268
					addIconTitle: rl.addIconTitle || rl.newModalTitle,

					bifold: rlParms.bifold,
					open_row_details_in_modal: open_row_details_in_modal
					//show_breadcrumbs: true
				};

				//------------------------------------------------------------------------------------------------------------------------
				// 2.5. CUSTOM: RELATED LIST CALL WIDGET 
				//------------------------------------------------------------------------------------------------------------------------
				rl.widget = $sp.getWidget('discovertasker-widget-data-table', params);
				tab_widget_related_lists.push(rl);
			}
		}
		return tab_widget_related_lists;
	},

	_setDefaultTitle: function(rl){
		var title = rl.label;
		if (rl.plural && rl.plural != '') {
			title = rl.plural;
		}
		return title;
	},

	type: 'TaskWidgetData'
};
